import{_ as i,o as s,c as e,a2 as l}from"./chunks/framework.BRk9mohw.js";const k=JSON.parse('{"title":"Bonjour / mDNS 发现","description":"","frontmatter":{},"headers":[],"relativePath":"tools/gateway/bonjour.md","filePath":"tools/gateway/bonjour.md"}'),t={name:"tools/gateway/bonjour.md"};function n(o,a,d,h,p,c){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="bonjour-mdns-发现" tabindex="-1">Bonjour / mDNS 发现 <a class="header-anchor" href="#bonjour-mdns-发现" aria-label="Permalink to &quot;Bonjour / mDNS 发现&quot;">​</a></h1><p>OpenClaw 使用 Bonjour（mDNS / DNS-SD）作为<strong>仅 LAN 便利</strong>来发现活动的网关（WebSocket 端点）。它是尽力而为的，不能替代 SSH 或 Tailnet 连接。</p><h2 id="广域网-bonjour-通过-tailscale-单播-dns-sd" tabindex="-1">广域网 Bonjour（通过 Tailscale 单播 DNS-SD） <a class="header-anchor" href="#广域网-bonjour-通过-tailscale-单播-dns-sd" aria-label="Permalink to &quot;广域网 Bonjour（通过 Tailscale 单播 DNS-SD）&quot;">​</a></h2><p>如果节点和网关在不同网络上，多播 mDNS 不会跨过边界。你可以通过切换到<strong>单播 DNS-SD</strong>（&quot;广域网 Bonjour&quot;）通过 Tailscale 保持相同的发现体验。</p><p>高层步骤：</p><ol><li>在网关主机上运行一个 DNS 服务器（通过 Tailnet 可达）。</li><li>在专用区域下发布 <code>_openclaw-gw._tcp</code> 的 DNS-SD 记录（例如：<code>openclaw.internal.</code>）。</li><li>配置 Tailscale <strong>split DNS</strong>，以便你的选定域通过该 DNS 服务器解析供客户端使用（包括 iOS）。</li></ol><p>OpenClaw 支持任何发现域；<code>openclaw.internal.</code> 只是一个例子。iOS/Android 节点同时浏览 <code>local.</code> 和你配置的广域网域。</p><h3 id="网关配置-推荐" tabindex="-1">网关配置（推荐） <a class="header-anchor" href="#网关配置-推荐" aria-label="Permalink to &quot;网关配置（推荐）&quot;">​</a></h3><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  gateway</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">bind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tailnet&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// tailnet-only (recommended)</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  discovery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">wideArea</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// enables wide-area DNS-SD publishing</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="一次性-dns-服务器设置-网关主机" tabindex="-1">一次性 DNS 服务器设置（网关主机） <a class="header-anchor" href="#一次性-dns-服务器设置-网关主机" aria-label="Permalink to &quot;一次性 DNS 服务器设置（网关主机）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dns</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span></span></code></pre></div><p>这安装 CoreDNS 并配置它：</p><ul><li>仅在网关的 Tailscale 接口上监听端口 53</li><li>从 <code>~/.openclaw/dns/&lt;domain&gt;.db</code> 提供你选择的域（例如 <code>openclaw.internal.</code>）</li></ul><p>从 tailnet 连接的机器验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _openclaw-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw.internal.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TAILNET_IPV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">4&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 53</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _openclaw-gw._tcp.openclaw.internal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PTR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span></span></code></pre></div><h3 id="tailscale-dns-设置" tabindex="-1">Tailscale DNS 设置 <a class="header-anchor" href="#tailscale-dns-设置" aria-label="Permalink to &quot;Tailscale DNS 设置&quot;">​</a></h3><p>在 Tailscale 管理控制台中：</p><ul><li>添加一个名称服务器指向网关的 tailnet IP（UDP/TCP 53）。</li><li>添加 split DNS，以便你的发现域使用该名称服务器。</li></ul><p>一旦客户端接受 tailnet DNS，iOS 节点可以在你的发现域中浏览 <code>_openclaw-gw._tcp</code>，而无需多播。</p><h3 id="网关监听器安全-推荐" tabindex="-1">网关监听器安全（推荐） <a class="header-anchor" href="#网关监听器安全-推荐" aria-label="Permalink to &quot;网关监听器安全（推荐）&quot;">​</a></h3><p>网关 WS 端口（默认 <code>18789</code>）默认绑定到环回。对于 LAN/tailnet 访问，明确绑定并保持认证启用。</p><p>对于仅 tailnet 设置：</p><ul><li>在 <code>~/.openclaw/openclaw.json</code> 中设置 <code>gateway.bind: &quot;tailnet&quot;</code>。</li><li>重启网关（或重启 macOS 菜单栏应用）。</li></ul><h2 id="什么在广播" tabindex="-1">什么在广播 <a class="header-anchor" href="#什么在广播" aria-label="Permalink to &quot;什么在广播&quot;">​</a></h2><p>只有网关广播 <code>_openclaw-gw._tcp</code>。</p><h2 id="服务类型" tabindex="-1">服务类型 <a class="header-anchor" href="#服务类型" aria-label="Permalink to &quot;服务类型&quot;">​</a></h2><ul><li><code>_openclaw-gw._tcp</code> — 网关传输信标（由 macOS/iOS/Android 节点使用）。</li></ul><h2 id="txt-键-非秘密提示" tabindex="-1">TXT 键（非秘密提示） <a class="header-anchor" href="#txt-键-非秘密提示" aria-label="Permalink to &quot;TXT 键（非秘密提示）&quot;">​</a></h2><p>网关广播小的非秘密提示以使 UI 流程更方便：</p><ul><li><code>role=gateway</code></li><li><code>displayName=&lt;friendly name&gt;</code></li><li><code>lanHost=&lt;hostname&gt;.local</code></li><li><code>gatewayPort=&lt;port&gt;</code>（网关 WS + HTTP）</li><li><code>gatewayTls=1</code>（仅在启用 TLS 时）</li><li><code>gatewayTlsSha256=&lt;sha256&gt;</code>（仅在启用 TLS 且指纹可用时）</li><li><code>canvasPort=&lt;port&gt;</code>（仅在启用画布主机时；目前与 <code>gatewayPort</code> 相同）</li><li><code>sshPort=&lt;port&gt;</code>（默认 22 未覆盖时）</li><li><code>transport=gateway</code></li><li><code>cliPath=&lt;path&gt;</code>（可选；可运行 <code>openclaw</code> 入口点的绝对路径）</li><li><code>tailnetDns=&lt;magicdns&gt;</code>（可选提示，当 Tailnet 可用时）</li></ul><p>安全说明：</p><ul><li>Bonjour/mDNS TXT 记录是<strong>未认证的</strong>。客户端不得将 TXT 视为权威路由。</li><li>客户端应使用解析的服务端点（SRV + A/AAAA）进行路由。将 <code>lanHost</code>、<code>tailnetDns</code>、<code>gatewayPort</code> 和 <code>gatewayTlsSha256</code> 视为仅提示。</li><li>TLS 固定不得允许广告的 <code>gatewayTlsSha256</code> 覆盖先前存储的固定。</li><li>iOS/Android 节点应将基于发现的直接连接视为<strong>仅 TLS</strong> 并在信任首次指纹之前需要明确的用户确认。</li></ul><h2 id="在-macos-上调试" tabindex="-1">在 macOS 上调试 <a class="header-anchor" href="#在-macos-上调试" aria-label="Permalink to &quot;在 macOS 上调试&quot;">​</a></h2><p>有用的内置工具：</p><ul><li><p>浏览实例：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _openclaw-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local.</span></span></code></pre></div></li><li><p>解析一个实例（替换 <code>&lt;instance&gt;</code>）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;instance&gt;&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _openclaw-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local.</span></span></code></pre></div></li></ul><p>如果浏览工作但解析失败，你通常遇到 LAN 策略或 mDNS 解析器问题。</p><h2 id="在网关日志中调试" tabindex="-1">在网关日志中调试 <a class="header-anchor" href="#在网关日志中调试" aria-label="Permalink to &quot;在网关日志中调试&quot;">​</a></h2><p>网关写入滚动日志文件（在启动时打印为 <code>gateway log file: ...</code>）。查找 <code>bonjour:</code> 行，特别是：</p><ul><li><code>bonjour: advertise failed ...</code></li><li><code>bonjour: ... name conflict resolved</code> / <code>hostname conflict resolved</code></li><li><code>bonjour: watchdog detected non-announced service ...</code></li></ul><h2 id="在-ios-节点上调试" tabindex="-1">在 iOS 节点上调试 <a class="header-anchor" href="#在-ios-节点上调试" aria-label="Permalink to &quot;在 iOS 节点上调试&quot;">​</a></h2><p>iOS 节点使用 <code>NWBrowser</code> 发现 <code>_openclaw-gw._tcp</code>。</p><p>要捕获日志：</p><ul><li>设置 → 网关 → 高级 → <strong>发现调试日志</strong></li><li>设置 → 网关 → 高级 → <strong>发现日志</strong> → 复现 → <strong>复制</strong></li></ul><p>日志包括浏览器状态转换和结果集更改。</p><h2 id="常见失败模式" tabindex="-1">常见失败模式 <a class="header-anchor" href="#常见失败模式" aria-label="Permalink to &quot;常见失败模式&quot;">​</a></h2><ul><li><strong>Bonjour 不跨网络</strong>：使用 Tailnet 或 SSH。</li><li><strong>多播被阻止</strong>：某些企业/公共 WiFi 阻止 mDNS。</li><li><strong>防火墙阻止</strong>：确保 UDP 端口 5353 对本地网络开放。</li></ul>`,46)])])}const g=i(t,[["render",n]]);export{k as __pageData,g as default};
